// Helper functions
export function getItinerary(slug) {
  return cityItineraries[slug] || null;
}

export function getAllItinerarySlugs() {
  return Object.keys(cityItineraries);
}

export function getRelatedItineraries(currentSlug, limit = 4) {
  const current = cityItineraries[currentSlug];
  if (!current) return [];

  return Object.values(cityItineraries)
    .filter(it => it.slug !== currentSlug)
    .sort((a, b) => {
      // Prioritize same city different days
      const aMatch = a.city === current.city ? 2 : 0;
      const bMatch = b.city === current.city ? 2 : 0;
      return bMatch - aMatch;
    })
    .slice(0, limit);
}
